module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output [15:0] result
);

    parameter ST_IDLE = 3'b000;
    parameter ST_SUB = 3'b001;
    parameter ST_MUX = 3'b010;
    parameter ST_SHIFT = 3'b011;
    parameter ST_DONE = 3'b100;

    reg [2:0] state, next_state;
    reg [15:0] sub_result, next_sub_result;
    reg [15:0] neg_divisor, next_neg_divisor;
    reg [23:0] sr, next_sr;
    reg [15:0] rem, next_rem;
    reg [15:0] quotient, next_quotient;
    reg [3:0] cnt, next_cnt;
    reg start_cnt, next_start_cnt;
    reg msb_cnt, next_msb_cnt;
    reg mux_sel, next_mux_sel;
    reg cout, next_cout;

    assign result = {rem, quotient};

    assign msb_cnt = cnt[3];
    assign mux_sel = sub_result[15];
    assign sub_cout = sub_result[15];

    always @(*) begin
        case (state)
            ST_IDLE: begin
                if (opn_valid & !res_valid) begin
                    next_sub_result = 16'd0;
                    next_neg_divisor = 16'd0;
                    next_sr = {16'd0, dividend};
                    next_rem = 16'd0;
                    next_quotient = 16'd0;
                    next_cnt = 4'd1;
                    next_start_cnt = 1'b1;
                    next_mux_sel = 1'b0;
                    next_cout = 1'b0;
                    next_state = ST_SUB;
                end else begin
                    next_sub_result = sub_result;
                    next_neg_divisor = neg_divisor;
                    next_sr = sr;
                    next_rem = rem;
                    next_quotient = quotient;
                    next_cnt = cnt;
                    next_start_cnt = start_cnt;
                    next_mux_sel = mux_sel;
                    next_cout = cout;
                    next_state = ST_IDLE;
                end
            end
            ST_SUB: begin
                if (msb_cnt) begin
                    next_sub_result = 16'd0;
                    next_neg_divisor = neg_divisor;
                    next_sr = sr;
                    next_rem = sr[15:0];
                    next_quotient = quotient;
                    next_cnt = 4'd1;
                    next_start_cnt = 1'b0;
                    next_mux_sel = 1'b0;
                    next_cout = 1'b0;
                    next_state = ST_DONE;
                end else begin
                    next_sub_result = sub_result;
                    next_neg_divisor = neg_divisor;
                    next_sr = sr;
                    next_rem = rem;
                    next_quotient = quotient;
                    next_cnt = cnt + 4'd1;
                    next_start_cnt = 1'b0;
                    next_mux_sel = 1'b0;
                    next_cout = 1'b0;
                    next_state = ST_MUX;
                end
            end
            ST_MUX: begin
                next_sub_result = sub_cout ? neg_divisor : sub_result;
                next_neg_divisor = neg_divisor;
                next_sr = mux_sel ? sr : {sr[23:1], mux_sel};
                next_rem = rem;
                next_quotient = quotient;
                next_cnt = cnt;
                next_start_cnt = 1'b0;
                next_mux_sel = mux_sel;
                next_cout = cout;
                next_state = ST_SHIFT;
            end
            ST_SHIFT: begin
                if (msb_cnt) begin
                    next_sub_result = 16'd0;
                    next_neg_divisor = neg_divisor;
                    next_sr = sr;
                    next_rem = sr[15:0];
                    next_quotient = quotient;
                    next_cnt = 4'd1;
                    next_start_cnt = 1'b0;
                    next_mux_sel = 1'b0;
                    next_cout = 1'b0;
                    next_state = ST_DONE;
                end else begin
                    next_sub_result = sub_result;
                    next_neg_divisor = neg_divisor;
                    next_sr = sr;
                    next_rem = rem;
                    next_quotient = quotient;
                    next_cnt = cnt + 4'd1;
                    next_start_cnt = 1'b0;
                    next_mux_sel = mux_sel;
                    next_cout = cout;
                    next_state = ST_MUX;
                end
            end
            ST_DONE: begin
                next_sub_result = 16'd0;
                next_neg_divisor = 16'd0;
                next_sr = 16'd0;
                next_rem = 16'd0;
                next_quotient = 16'd0;
                next_cnt = 4'd0;
                next_start_cnt = 1'b0;
                next_mux_sel = 1'b0;
                next_cout = 1'b0;
                next_state = ST_IDLE;
            end
            default: begin
                next_sub_result = 16'd0;
                next_neg_divisor = 16'd0;
                next_sr = 16'd0;
                next_rem = 16'd0;
                next_quotient = 16'd0;
                next_cnt = 4'd0;
                next_start_cnt = 1'b0;
                next_mux_sel = 1'b0;
                next_cout = 1'b0;
                next_state = ST_IDLE;
            end
        endcase
    end

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            state <= ST_IDLE;
            sub_result <= 16'd0;
            neg_divisor <= 16'd0;
            sr <= 16'd0;
            rem <= 16'd0;
            quotient <= 16'd0;
            cnt <= 4'd0;
            start_cnt <= 1'b0;
            mux_sel <= 1'b0;
            cout <= 1'b0;
        end else begin
            state <= next_state;
            sub_result <= next_sub_result;
            neg_divisor <= next_neg_divisor;
            sr <= next_sr;
            rem <= next_rem;
            quotient <= next_quotient;
            cnt <= next_cnt;
            start_cnt <= next_start_cnt;
            mux_sel <= next_mux_sel;
            cout <= next_cout;
        end
    end

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            res_valid <= 1'b0;
        end else begin
            if (cnt == 4'd8) begin
                res_valid <= 1'b1;
            end else begin
                if (res_valid & res_ready) begin
                    res_valid <= 1'b0;
                end else begin
                    res_valid <= res_valid;
                end
            end
        end
    end

endmodule
